import { existsSync, statSync, readFileSync, rmSync } from "node:fs";
import { join } from "node:path";

const root = process.cwd();

// Cleanup 0-byte index.d.ts generated by napi cli in prebuilds
const staleDts = join(root, "prebuilds/index.d.ts");
if (existsSync(staleDts)) {
  try {
    rmSync(staleDts, { force: true });
    console.log("Cleaned up stale prebuilds/index.d.ts file.");
  } catch (err) {
    console.warn(`Could not delete prebuilds/index.d.ts: ${err.message}`);
  }
}

// JS build artifacts that must be present before publishing.
const requiredDist = ["dist/index.js", "dist/index.cjs", "dist/index.d.ts"];

// One compiled native binary per supported platform.
const requiredTargets = [
  "win32-x64-msvc",
  "linux-x64-gnu",
  "linux-arm64-gnu",
  "darwin-x64",
  "darwin-arm64",
  "linux-x64-musl",
  "linux-arm64-musl",
  "linux-arm-gnueabihf",
  "linux-arm-musleabihf",
];

const SIGNATURES = [
  Buffer.from("zlib-ng", "utf8"),
  Buffer.from("zng_inflate", "utf8"),
];

const errors = [];

for (const rel of requiredDist) {
  const full = join(root, rel);
  if (!existsSync(full)) {
    errors.push(`Missing required build artifact: ${rel}`);
  }
}

for (const triple of requiredTargets) {
  const rel = `prebuilds/zlibsync_rs.${triple}.node`;
  const full = join(root, rel);
  if (!existsSync(full)) {
    errors.push(`Missing required native binary: ${rel}`);
    continue;
  }
  const size = statSync(full).size;
  if (size <= 0) {
    errors.push(`Native binary is empty: ${rel}`);
    continue;
  }

  // Verify the binary compiles with zlib-ng backend
  const buffer = readFileSync(full);
  const hasZlibNg = SIGNATURES.some(sig => buffer.indexOf(sig) !== -1);
  if (!hasZlibNg) {
    errors.push(`Binary ${rel} does not contain zlib-ng signatures (using miniz_oxide fallback). Run a clean cross-compilation build.`);
  }
}

if (errors.length > 0) {
  console.error("Prepublish validation failed:\n");
  for (const err of errors) {
    console.error(`  - ${err}`);
  }
  process.exit(1);
}

console.log("Prepublish validation passed.");

